  account?: Prisma.AccountOmit
  session?: Prisma.SessionOmit
  verificationToken?: Prisma.VerificationTokenOmit
  user?: Prisma.UserOmit
  ffxivCharacter?: Prisma.FfxivCharacterOmit
  estate?: Prisma.EstateOmit
  estateVerification?: Prisma.EstateVerificationOmit
  estatePendingTransfer?: Prisma.EstatePendingTransferOmit
  image?: Prisma.ImageOmit
  venueDetails?: Prisma.VenueDetailsOmit
  venueStaff?: Prisma.VenueStaffOmit
  like?: Prisma.LikeOmit
  comment?: Prisma.CommentOmit
  lodestoneVerification?: Prisma.LodestoneVerificationOmit
  legalPage?: Prisma.LegalPageOmit
  siteSettings?: Prisma.SiteSettingsOmit
  estateClaimRequest?: Prisma.EstateClaimRequestOmit
  collection?: Prisma.CollectionOmit
  collectionEstate?: Prisma.CollectionEstateOmit
  conversation?: Prisma.ConversationOmit
  message?: Prisma.MessageOmit
  pushSubscription?: Prisma.PushSubscriptionOmit
  fcOverrideRequest?: Prisma.FcOverrideRequestOmit
  fcOverride?: Prisma.FcOverrideOmit
  moderationLog?: Prisma.ModerationLogOmit
